import React from 'react'
import {useState} from 'react'

function App() {

 let [cap,checkCap] = useState(false);
 let [small,checkSmall] = useState(false);
 let [special,checkSpecial] = useState(false);
 let [number,checkNumber] = useState(false);

 let handleChange = (e)=>
 {
  let passwd = e.target.value;
  checkCap(/[A-Z]/.test(passwd[0]));
  checkSmall(/[a-z]/.test(passwd));
  checkSpecial(/[!@#$%^&*()]/.test(passwd));
  checkNumber(/[0-9]/.test(passwd));
 }
 return (
  <>
  <h1>Password Validator</h1>
  <br />
  <input type="text" onChange={handleChange} placeholder="Enter valid password..." />
  <br /><br />
  <p style={{color : cap ? "green" : "red"}}>First character should be capital</p>
  <p style={{color : small ? "green" : "red"}}>Must contain one small letter</p>
  <p style={{color : special ? "green" : "red"}}>Must contain one special character</p>
  <p style={{color : number ? "green" : "red"}}>Must contain one number (0-9)</p>
  </>
 )
}

export default App